UPDATE investigaciones SET supuestosEstructurados = '[{"id":1,"supuesto":"El almacenamiento de Presa Huites se mantiene dentro del rango operativo normal (2,500-3,000 hm³)","impacto":"Alto","sensibilidad":"Crítico","verificado":true},{"id":2,"supuesto":"La variabilidad climática (IVC) no excede 1.5 desviaciones estándar respecto a la media histórica","impacto":"Alto","sensibilidad":"Crítico","verificado":false},{"id":3,"supuesto":"La capacidad institucional de absorción (CAL) permanece constante sin reformas administrativas","impacto":"Medio","sensibilidad":"Moderado","verificado":true},{"id":4,"supuesto":"El Índice de Saturación de Demanda (ISD) se calcula con datos oficiales de CONAGUA sin ajustes locales","impacto":"Medio","sensibilidad":"Moderado","verificado":true},{"id":5,"supuesto":"No se construyen nuevas presas o infraestructura hidráulica mayor en la región durante el periodo","impacto":"Bajo","sensibilidad":"Bajo","verificado":false}]', indiceRobustez = 0.80, fechaCierreSemantico = NOW() WHERE numero = 2;

UPDATE investigaciones SET supuestosEstructurados = '[{"id":1,"supuesto":"Los datos de cobertura forestal de INEGI son representativos de la realidad local de Choix","impacto":"Alto","sensibilidad":"Crítico","verificado":true},{"id":2,"supuesto":"La tasa de deforestación observada en el periodo 2015-2020 se mantiene constante hasta 2026","impacto":"Alto","sensibilidad":"Crítico","verificado":false},{"id":3,"supuesto":"El cambio de uso de suelo se debe principalmente a expansión agrícola y ganadera, no a minería o urbanización","impacto":"Medio","sensibilidad":"Moderado","verificado":true},{"id":4,"supuesto":"No ocurrieron incendios forestales masivos no documentados que alteren significativamente la cobertura","impacto":"Alto","sensibilidad":"Crítico","verificado":false},{"id":5,"supuesto":"La tasa de reforestación es inferior al 10% de la tasa de deforestación","impacto":"Medio","sensibilidad":"Moderado","verificado":false}]', indiceRobustez = 0.60, fechaCierreSemantico = NOW() WHERE numero = 3;

UPDATE investigaciones SET supuestosEstructurados = '[{"id":1,"supuesto":"Los datos de matrícula escolar de la SEP son completos y actualizados hasta el ciclo 2024-2025","impacto":"Alto","sensibilidad":"Crítico","verificado":true},{"id":2,"supuesto":"La tasa de crecimiento poblacional en edad escolar se mantiene constante en 2.5% anual","impacto":"Alto","sensibilidad":"Crítico","verificado":false},{"id":3,"supuesto":"La capacidad instalada de infraestructura educativa no aumenta significativamente sin inversión pública","impacto":"Medio","sensibilidad":"Moderado","verificado":true},{"id":4,"supuesto":"El índice de deserción escolar se mantiene en niveles históricos (15-20% en secundaria)","impacto":"Medio","sensibilidad":"Moderado","verificado":true},{"id":5,"supuesto":"No se implementan programas masivos de educación a distancia que alteren la demanda de infraestructura física","impacto":"Bajo","sensibilidad":"Bajo","verificado":false}]', indiceRobustez = 0.80, fechaCierreSemantico = NOW() WHERE numero = 4;

UPDATE investigaciones SET supuestosEstructurados = '[{"id":1,"supuesto":"Los datos de infraestructura de salud de la Secretaría de Salud son actualizados y completos","impacto":"Alto","sensibilidad":"Crítico","verificado":true},{"id":2,"supuesto":"La demanda de servicios de salud crece proporcionalmente al crecimiento poblacional (2% anual)","impacto":"Alto","sensibilidad":"Crítico","verificado":false},{"id":3,"supuesto":"No ocurren epidemias o pandemias que saturen temporalmente el sistema de salud","impacto":"Alto","sensibilidad":"Crítico","verificado":false},{"id":4,"supuesto":"La tasa de ocupación hospitalaria promedio se mantiene en 70-80% sin picos estacionales extremos","impacto":"Medio","sensibilidad":"Moderado","verificado":true},{"id":5,"supuesto":"El personal médico disponible se mantiene constante sin migración significativa hacia otras regiones","impacto":"Medio","sensibilidad":"Moderado","verificado":false}]', indiceRobustez = 0.60, fechaCierreSemantico = NOW() WHERE numero = 5;

UPDATE investigaciones SET supuestosEstructurados = '[{"id":1,"supuesto":"Los datos de infraestructura vial de SCT son representativos del estado actual de las carreteras","impacto":"Alto","sensibilidad":"Crítico","verificado":true},{"id":2,"supuesto":"El flujo vehicular crece a una tasa del 4% anual sin cambios en patrones de movilidad","impacto":"Alto","sensibilidad":"Crítico","verificado":false},{"id":3,"supuesto":"No se construyen nuevas carreteras o ampliaciones significativas en el periodo analizado","impacto":"Medio","sensibilidad":"Moderado","verificado":false},{"id":4,"supuesto":"La tasa de deterioro de pavimento se mantiene constante sin mantenimiento preventivo","impacto":"Medio","sensibilidad":"Moderado","verificado":true},{"id":5,"supuesto":"Los cuellos de botella identificados no se agravan por eventos climáticos extremos (deslaves, inundaciones)","impacto":"Bajo","sensibilidad":"Bajo","verificado":false}]', indiceRobustez = 0.80, fechaCierreSemantico = NOW() WHERE numero = 6;

